import React from 'react';

const CommentsModeration = () => {
  const comments = [
    { id: 1, author: 'DarkLord', text: 'Great chapter!', flagged: false },
    { id: 2, author: 'Guest007', text: 'Spam link example', flagged: true },
    { id: 3, author: 'MangaFan', text: 'Waiting for next upload', flagged: false }
  ];

  return (
    <div>
      <h2>Comments Moderation</h2>
      <div className="admin-card">
        {comments.map((comment) => (
          <div key={comment.id} className="admin-row">
            <strong>{comment.author}</strong>
            <span>{comment.text}</span>
            <span>{comment.flagged ? 'Flagged' : 'OK'}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

export default CommentsModeration;
